module ring_counter_4bit(
    input clk,
    input rst,
    output [3:0] count
);

    reg [3:0] reset_reg;

    always @(posedge clk) begin
        if (!rst) begin
            reset_reg <= 4'b1000;
        end else begin
            reset_reg <= {reset_reg[2:0], reset_reg[3]};
        end
    end

    assign count = reset_reg;

endmodule
